const inp=$input.first().json||{};
function fromStr(s){s=String(s).trim();if(s.startsWith('{')){try{return JSON.parse(s);}catch(e){}}return {};}
let raw=(inp.query!==undefined)?inp.query:inp; let a={};
if(typeof raw==='string'){a=fromStr(raw);}
else if(raw&&typeof raw==='object'){
  if(raw.agent_id!==undefined||raw.severity!==undefined||raw.cve!==undefined||raw.size!==undefined){a=raw;}
  else{const f=Object.values(raw)[0]; a=(typeof f==='string')?fromStr(f):(f&&typeof f==='object'?f:raw);}
}
let agent=String(a.agent_id||a.agent||'').trim();
if(agent==='1'||/ubuntu.?2|agent_ubuntu2/i.test(agent))agent='001';
if(agent==='2'||/win/i.test(agent))agent='002';
let severity=String(a.severity||'').trim();        // Critical|High|Medium|Low
if(severity)severity=severity.charAt(0).toUpperCase()+severity.slice(1).toLowerCase();
let cve=String(a.cve||a.id||'').trim().toUpperCase();
let size=Number(a.size)||20;
const filt=[];
if(agent)filt.push({term:{'agent.id':agent}});
if(severity)filt.push({term:{'vulnerability.severity':severity}});
if(cve)filt.push({term:{'vulnerability.id':cve}});
const query=filt.length?{bool:{filter:filt}}:{match_all:{}};
return [{json:{size,query}}];

const r=$input.first().json||{};
const hits=(r.hits&&r.hits.hits)||[];
const items=hits.map(h=>{const s=h._source||{};const v=s.vulnerability||{};const p=s.package||{};const ag=s.agent||{};
  return {cve:v.id, severity:v.severity, score:(v.score&&v.score.base), package:p.name, version:p.version, agent:ag.name,
          desc:(v.description||'').slice(0,160)};});
const total=(r.hits&&r.hits.total&&(r.hits.total.value??r.hits.total))||0;
return [{json:{count:hits.length, total_matching:total, vulnerabilities:items}}];
